import React, { useEffect, useState } from 'react';
import {
  Container, Typography, Paper, Grid, TextField, FormControlLabel, Switch,
  Button, CircularProgress, Alert, Snackbar, Box, MenuItem
} from '@mui/material';
import { getStripeConfig, updateStripeConfig, type StripeConfig as StripeConfigType } from '../../services/stripeService';

// Extend form with local-only confirmation fields
interface StripeConfigForm extends Omit<StripeConfigType, 'updatedAt'> {
  confirmSecretKey: string;
  confirmWebhookSecret: string;
}

const StripeConfig: React.FC = () => {
  // Prefer checking admin token; routes should also be protected by AdminProtectedRoute
  const hasAdminToken = typeof window !== 'undefined' && !!localStorage.getItem('adminToken');

  const [config, setConfig] = useState<StripeConfigForm>({
    isActive: false,
    publishableKey: '',
    secretKey: '',
    webhookSecret: '',
    commissionRate: 0,
    currency: 'USD',
    confirmSecretKey: '',
    confirmWebhookSecret: '',
  });

  const [loading, setLoading] = useState(true);   // initial load
  const [saving, setSaving] = useState(false);    // submit state
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  // Load config on mount (if admin)
  useEffect(() => {
    const load = async () => {
      try {
        setLoading(true);
        const data = await getStripeConfig();
        setConfig(prev => ({
          ...prev,
          ...data,
          isActive: data?.isActive ?? false,
          publishableKey: data?.publishableKey ?? '',
          secretKey: data?.secretKey ?? '',
          webhookSecret: data?.webhookSecret ?? '',
          commissionRate: data?.commissionRate ?? 0,
          currency: data?.currency ?? 'USD',
          confirmSecretKey: '',
          confirmWebhookSecret: '',
        }));
      } catch (e) {
        setError('Failed to load configuration');
      } finally {
        setLoading(false);
      }
    };

    if (hasAdminToken) load();
    else setLoading(false);
  }, [hasAdminToken]);

  // Text inputs
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    setConfig(prev => ({
      ...prev,
      [name]:
        name === 'commissionRate'
          ? Number(value)
          : type === 'checkbox'
          ? (e.target as HTMLInputElement).checked
          : value,
    }));
  };

  // Switch inputs (MUI signature)
  const handleSwitch = (name: keyof StripeConfigForm) =>
    (_e: React.ChangeEvent<HTMLInputElement>, checked: boolean) => {
      setConfig(prev => ({ ...prev, [name]: checked }));
    };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    // Basic validations
    if (!config.publishableKey.trim()) return setError('Publishable key is required');
    if (!config?.secretKey?.trim()) return setError('Secret key is required');
    if (config.secretKey !== config.confirmSecretKey)
      return setError('Secret keys do not match');

    if (config.webhookSecret && config.confirmWebhookSecret && config.webhookSecret !== config.confirmWebhookSecret) {
      return setError('Webhook secrets do not match');
    }

    setSaving(true);
    try {
      const { confirmSecretKey, confirmWebhookSecret, ...payload } = config;
      await updateStripeConfig(payload);

      setSuccess('Configuration saved successfully');

      // Refresh values from API
      const updated = await getStripeConfig();
      setConfig(prev => ({
        ...prev,
        ...updated,
        confirmSecretKey: '',
        confirmWebhookSecret: '',
      }));
    } catch (err: any) {
      setError(err?.message || 'Failed to save configuration');
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="200px">
        <CircularProgress />
      </Box>
    );
  }

  if (!hasAdminToken) {
    return (
      <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
        <Alert severity="error">You do not have permission to access this page.</Alert>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
      <Typography variant="h4" gutterBottom>Stripe Configuration</Typography>

      {!!error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

      <Paper sx={{ p: 3, mt: 3 }}>
        <form onSubmit={handleSubmit}>
          <Grid container spacing={3}>
            <Grid item xs={12}>
              <FormControlLabel
                control={
                  <Switch
                    checked={config.isActive}
                    onChange={handleSwitch('isActive')}
                    name="isActive"
                    disabled={saving}
                  />
                }
                label="Enable Stripe Payments"
              />
            </Grid>

            <Grid item xs={12} md={6}>
              <TextField
                fullWidth
                label="Publishable Key"
                name="publishableKey"
                value={config.publishableKey}
                onChange={handleChange}
                required
                disabled={saving}
              />
            </Grid>

            <Grid item xs={12} md={6}>
              <TextField
                select
                fullWidth
                label="Currency"
                name="currency"
                value={config.currency}
                onChange={handleChange}
                disabled={saving}
              >
                {['USD', 'EUR', 'GBP', 'CAD', 'AUD', 'JMD'].map(cur => (
                  <MenuItem key={cur} value={cur}>{cur}</MenuItem>
                ))}
              </TextField>
            </Grid>

            <Grid item xs={12} md={6}>
              <TextField
                fullWidth
                label="Secret Key"
                name="secretKey"
                type="password"
                value={config.secretKey}
                onChange={handleChange}
                required
                disabled={saving}
              />
            </Grid>

            <Grid item xs={12} md={6}>
              <TextField
                fullWidth
                label="Confirm Secret Key"
                name="confirmSecretKey"
                type="password"
                value={config.confirmSecretKey}
                onChange={handleChange}
                required
                disabled={saving}
              />
            </Grid>

            <Grid item xs={12} md={6}>
              <TextField
                fullWidth
                label="Webhook Secret"
                name="webhookSecret"
                type="password"
                value={config.webhookSecret}
                onChange={handleChange}
                disabled={saving}
              />
            </Grid>

            <Grid item xs={12} md={6}>
              <TextField
                fullWidth
                label="Confirm Webhook Secret"
                name="confirmWebhookSecret"
                type="password"
                value={config.confirmWebhookSecret}
                onChange={handleChange}
                disabled={saving}
              />
            </Grid>

            <Grid item xs={12} md={6}>
              <TextField
                fullWidth
                type="number"
                inputProps={{ step: '0.1', min: 0, max: 100 }}
                label="Commission Rate (%)"
                name="commissionRate"
                value={config.commissionRate}
                onChange={handleChange}
                disabled={saving}
              />
            </Grid>

            <Grid item xs={12}>
              <Button
                type="submit"
                variant="contained"
                color="primary"
                disabled={saving}
                startIcon={saving ? <CircularProgress size={18} /> : undefined}
              >
                {saving ? 'Saving…' : 'Save Configuration'}
              </Button>
            </Grid>
          </Grid>
        </form>
      </Paper>

      <Snackbar
        open={!!success}
        autoHideDuration={5000}
        onClose={() => setSuccess('')}
        message={success}
      />
    </Container>
  );
};

export default StripeConfig;

